// EvetestServer is the server API for Evetest service.
// All implementations must embed UnimplementedEvetestServer
// for forward compatibility.
//
// Evetest provides functions for interacting with the evetest framework.
// It is used by evetest CLI.
type EvetestServer interface {
	// Continue test execution until the end/failure or another checkpoint.
	Continue(context.Context, *ContinueRequest) (*ContinueResponse, error)
	// Exit the test early, marking it as skipped or incomplete.
	Exit(context.Context, *ExitRequest) (*ExitResponse, error)
	// Returns current test execution state and active devices.
	Status(context.Context, *StatusRequest) (*StatusResponse, error)
	// Immediately force power cycle of the EVE device.
	HardRebootEVEDevice(context.Context, *EVEDeviceRequest) (*EVERebootResponse, error)
	// Request a clean OS-level reboot on the EVE device.
	SoftRebootEVEDevice(context.Context, *EVEDeviceRequest) (*EVERebootResponse, error)
	// Fetch the current configuration submitted to the EVE device.
	GetEVEConfig(context.Context, *EVEDeviceRequest) (*EVEConfigResponse, error)
	// Stream real-time system info from EVE device (ZInfoDevice).
	GetEVEInfo(*EVEDeviceStreamableRequest, grpc.ServerStreamingServer[EVEInfoResponse]) error
	// Stream real-time metrics from EVE device (deviceMetric).
	GetEVEMetrics(*EVEDeviceStreamableRequest, grpc.ServerStreamingServer[EVEMetricsResponse]) error
	// Stream logs from EVE device (agent logs, kernel logs, etc).
	GetEVELogs(*EVEDeviceStreamableRequest, grpc.ServerStreamingServer[LogMessage]) error
	// Get current console output from the EVE device.
	GetEVEConsoleOutput(context.Context, *EVEDeviceRequest) (*ConsoleOutputResponse, error)
	// Stream application-specific info from a device (ZInfoApp).
	GetAppInfo(*AppRequest, grpc.ServerStreamingServer[AppInfoResponse]) error
	// Stream application-level metrics from a device (appMetric).
	GetAppMetrics(*AppRequest, grpc.ServerStreamingServer[AppMetricsResponse]) error
	// Stream logs from an EVE-managed application.
	GetAppLogs(*AppRequest, grpc.ServerStreamingServer[LogMessage]) error
	// Stream flow logs and DNS request logs for an application.
	GetAppFlowLogs(*AppRequest, grpc.ServerStreamingServer[AppFlowLogsResponse]) error
	// Stream info (ZInfoNetworkInstance) about a network instance (NI).
	GetNIInfo(*NIRequest, grpc.ServerStreamingServer[NIInfoResponse]) error
	// Stream metrics (ZMetricNetworkInstance) for a network instance.
	GetNIMetrics(*NIRequest, grpc.ServerStreamingServer[NIMetricsResponse]) error
	// Stream summary information for the entire Kubernetes cluster.
	GetClusterInfo(*ClusterRequest, grpc.ServerStreamingServer[ClusterInfoResponse]) error
	// Stream information about ongoing cluster updates.
	GetClusterUpdateInfo(*ClusterRequest, grpc.ServerStreamingServer[ClusterUpdateInfoResponse]) error
	// Stream metrics for the Kubernetes cluster (KubeClusterMetrics).
	GetClusterMetrics(*ClusterRequest, grpc.ServerStreamingServer[ClusterMetricsResponse]) error
	// Obtain debug information from a device (eve-info tarball).
	CollectInfo(context.Context, *EVEDeviceRequest) (*CollectInfoResponse, error)
	// ConnectTunnelToEVE opens a single TCP tunnel over gRPC to a given port on
	// an EVE device. The client first sends a ConnectTunnelToEVERequest with a
	// Connect payload; the server responds with TunnelConnected once the EVE-side
	// TCP connection is up. After that, both sides exchange raw bytes.
	ConnectTunnelToEVE(grpc.BidiStreamingServer[ConnectTunnelToEVERequest, ConnectTunnelToEVEResponse]) error
	// ConnectConsoleToEVE establishes an interactive serial-console session over
	// gRPC. The client first sends a Connect payload; the server responds with
	// ConsoleProperties, then both sides exchange raw bytes.
	ConnectConsoleToEVE(grpc.BidiStreamingServer[ConnectConsoleToEVERequest, ConnectConsoleToEVEResponse]) error
	// Get overall SDN (network emulator) status.
	GetSDNStatus(context.Context, *SDNRequest) (*SDNStatusResponse, error)
	// Get the SDN's abstract model of the network.
	GetSDNNetworkModel(context.Context, *SDNRequest) (*SDNGetNetworkModelResponse, error)
	// Get the SDN configuration visualized as a Graphviz dot-formatted graph.
	GetSDNConfigGraph(context.Context, *SDNRequest) (*SDNConfigGraphResponse, error)
	// Stream SDN logs.
	StreamSDNLogs(*SDNRequest, grpc.ServerStreamingServer[LogMessage]) error
	// ConnectTunnelToSDN opens a TCP tunnel over gRPC to the SDN SSH port.
	// Same handshake as ConnectTunnelToEVE: Connect payload first, then raw bytes.
	ConnectTunnelToSDN(grpc.BidiStreamingServer[ConnectSSHTunnelToSDNRequest, ConnectSSHTunnelToSDNResponse]) error
	mustEmbedUnimplementedEvetestServer()
}

